div.p:
c
// phdr processing loop
for (i = 0; i < e_phnum; i++) {
if (ph[i].p_type == PT_LOAD) {
void* map = mmap(
(void*)ph[i].p_vaddr,
ph[i].p_memsz,
elf_prot(ph[i].p_flags),
MAP_FIXED | MAP_PRIVATE,
fd, ph[i].p_offset
);
if (ph[i].p_memsz > ph[i].p_filesz) {
memset(map + ph[i].p_filesz, 0,
ph[i].p_memsz - ph[i].p_filesz);
}
}
}
